mapper.select:
SELECT GATE_CD , MODULE_TYPE , SCREEN_ID , SCREEN_ID_ORG , SCREEN_NM , SCREEN_URL , USE_FLAG , DATA_AUTH_FLAG , REG_USER_ID , ('') AS SCREEN_NM_IMG , POPUP_NM AS POPUP_NM_IMG , REG_DATE , INSERT_FLAG, SCREEN_TYPE , DEVELOPER_CD , GRID_TYPE , EXCEL_OPTION , AUTH_IMG , HELP_INFO , PANEL_USE_FLAG , OUT_URL , POPUP , SHRINK_TO_FIT , APPROVAL_TYPE FROM ( SELECT SCRN.GATE_CD , SCRN.MODULE_TYPE , SCRN.SCREEN_ID , SCRN.SCREEN_ID AS SCREEN_ID_ORG , SCRN.SCREEN_URL , SCRN.USE_FLAG , SCRN.DATA_AUTH_FLAG , (SELECT UR.USER_NM FROM STOCUSER UR WHERE UR.GATE_CD = SCRN.GATE_CD AND UR.USER_ID = SCRN.REG_USER_ID) AS REG_USER_ID , 'U' AS INSERT_FLAG , SCRN.SCREEN_TYPE , SCRN.DEVELOPER_CD , SCRN.GRID_TYPE , SCRN.EXCEL_OPTION , (CASE WHEN HELP_TEXT_NUM IS NULL THEN (CASE WHEN HELP_ATT_FILE_NUM IS NULL THEN '' ELSE '1' END) ELSE '1' END) AS HELP_INFO , (SELECT CASE WHEN SUM(CASE WHEN (TEXT1, '-') != '-' OR (TEXT2, '-') != '-' OR (TEXT3, '-') != '-' OR (TEXT4, '-') != '-' THEN 1 ELSE 0 END) > 0 THEN 'Y' ELSE '' END FROM STOCCODD WHERE GATE_CD = SCRN.GATE_CD AND CODE_TYPE = 'SCRN_AUTH' AND LANG_CD = 'KO' AND CODE = SCRN.SCREEN_ID AND DEL_FLAG = '0') AS AUTH_IMG , (SCRN.PANEL_USE_FLAG, '0') AS PANEL_USE_FLAG , (SCRN.SHRINK_TO_FIT, '0') AS SHRINK_TO_FIT , SCRN.OUT_URL , SCRN.POPUP , GETMULTINAME(SCRN.GATE_CD, 'SC', #{ses.langCd}, '', SCRN.SCREEN_ID) AS SCREEN_NM , GETMULTINAME(SCRN.GATE_CD, 'SCP', #{ses.langCd}, '', SCRN.SCREEN_ID) AS POPUP_NM , (SCRN.REG_DATE, 'yyyyMMdd') AS REG_DATE , SCRN.APPROVAL_TYPE FROM STOCSCRN SCRN WHERE SCRN.GATE_CD = #{ses.gateCd} AND SCRN.DEL_FLAG = '0'
AND SCREEN_TYPE = #{SCREEN_TYPE}
AND MODULE_TYPE = #{MODULE_TYPE}
AND UPPER(SCREEN_ID) LIKE '%' UPPER(#{SCREEN_ID}) '%'
AND UPPER(SCREEN_URL) LIKE '%' UPPER(#{SCREEN_URL}) '%'
AND DEVELOPER_CD = #{DEVELOPER_CD}
AND UPPER(GETMULTINAME(SCRN.GATE_CD, 'SC', #{ses.langCd}, '', SCRN.SCREEN_ID)) LIKE '%' UPPER(#{SCREEN_NM}) '%'
) SC WHERE 1=1 ORDER BY MODULE_TYPE, SCREEN_ID

SELECT  COUNT(SCREEN_ID)
  FROM STOCSCRN
 WHERE GATE_CD = #{ses.gateCd}
   AND SCREEN_ID = #{SCREEN_ID}

mapper.insert:
        INSERT INTO STOCSCRN (
	          GATE_CD
	        , SCREEN_ID
	        , REG_DATE
	        , REG_USER_ID
	        , MOD_DATE
	        , MOD_USER_ID
	        , DEL_FLAG
	        , USE_FLAG
	        , MODULE_TYPE
	        , SCREEN_URL
	        , DATA_AUTH_FLAG
	        , SCREEN_TYPE
	        , DEVELOPER_CD
	        , GRID_TYPE
	        , EXCEL_OPTION
	        , PANEL_USE_FLAG
	        , SHRINK_TO_FIT
	        , APPROVAL_TYPE
        ) VALUES(
	          #{ses.gateCd}
	        , #{SCREEN_ID}
	        , SYSDATE
	        , #{ses.userId}
	        , SYSDATE
	        , #{ses.userId}
	        , '0'
	        , #{USE_FLAG}
	        , #{MODULE_TYPE}
	        , #{SCREEN_URL}
	        , #{DATA_AUTH_FLAG}
	        , #{SCREEN_TYPE}
	        , #{DEVELOPER_CD}
	        , #{GRID_TYPE}
	        , #{EXCEL_OPTION}
	        , #{PANEL_USE_FLAG}
	        , #{SHRINK_TO_FIT}
	        , #{APPROVAL_TYPE}
        )

mapper.update:
        UPDATE STOCSCRN SET
	          MOD_USER_ID = #{ses.userId}
	        , MOD_DATE = SYSDATE
	        , SCREEN_ID = #{SCREEN_ID}
	        , USE_FLAG = #{USE_FLAG}
	        , MODULE_TYPE = #{MODULE_TYPE}
	        , SCREEN_TYPE = #{SCREEN_TYPE}
	        , SCREEN_URL = #{SCREEN_URL}
	        , DATA_AUTH_FLAG = #{DATA_AUTH_FLAG}
	        , GRID_TYPE = #{GRID_TYPE}
	        , DEL_FLAG = '0'
	        , DEVELOPER_CD = #{DEVELOPER_CD}
	        , EXCEL_OPTION = #{EXCEL_OPTION}
	        , PANEL_USE_FLAG = #{PANEL_USE_FLAG}
            , OUT_URL = #{OUT_URL}
            , POPUP = #{POPUP}
            , SHRINK_TO_FIT = #{SHRINK_TO_FIT}
        	, APPROVAL_TYPE = #{APPROVAL_TYPE}
        WHERE GATE_CD = #{GATE_CD}
          AND SCREEN_ID = #{SCREEN_ID}

        UPDATE STOCSCRN SET
	          DEL_FLAG = '1'
	        , MOD_USER_ID = #{ses.userId}
	        , MOD_DATE = SYSDATE
        WHERE GATE_CD = #{GATE_CD}
        AND SCREEN_ID = #{SCREEN_ID_ORG}

UPDATE STOCSCRN SET
	  MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , HELP_TEXT_NUM = #{HELP_TEXT_NUM}
    , HELP_ATT_FILE_NUM = #{HELP_ATT_FILE_NUM}
 WHERE GATE_CD = #{ses.gateCd}
   AND SCREEN_ID = #{SCREEN_ID}

UPDATE STOCSCRN SET
	  MOD_DATE = SYSDATE
    , MOD_USER_ID = #{ses.userId}
    , HELP_TEXT_NUM = NULL
    , HELP_ATT_FILE_NUM = NULL
 WHERE GATE_CD = #{ses.gateCd}
   AND SCREEN_ID = #{SCREEN_ID}
